var e=[{id:`mercury`,name:`MERCURY`,a:12,e:.2,period:3,size:.5,color:`#b8a68f`,chakra:`#b8a68f`},{id:`venus`,name:`VENUS`,a:18,e:.006,period:8,size:.7,color:`#8b7a69`,chakra:`#d2691e`},{id:`earth`,name:`EARTH`,a:24,e:.017,period:12,size:.75,color:`#2a2a2a`,chakra:`#8B7355`},{id:`mars`,name:`MARS`,a:28,e:.0934,period:16,size:.8,color:`#c1440e`,chakra:`#ff4500`},{id:`saturn`,name:`SATURN`,a:32,e:.09,period:20,size:1,color:`#9d8b7a`,chakra:`#b8860b`},{id:`amethyst`,name:`AMETHYST`,a:42,e:.05,period:28,size:1.2,color:`#9b7aa8`,chakra:`#9d7e6a`}];function t(e,t,n){let r=n+t*Math.sin(n);r=n+t*Math.sin(r);let i=2*Math.atan2(Math.sqrt(1+t)*Math.sin(r/2),Math.sqrt(1-t)*Math.cos(r/2)),a=e*(1-t*t)/(1+t*Math.cos(i));return[a*Math.cos(i),a*Math.sin(i)]}export{t as n,e as t};